// V-Groove Pulley — BREP / replicad
// A flat disk pulley with a V-shaped drive-belt groove around the rim,
// a center bore, a keyway slot, and chamfered side rims.
//
// Coordinates: axis along Z, sits flat on the XY plane.

const { BREP } = api;

// --- Tunables ---
const R_OUTER     = 25;    // outer disk radius (50 mm dia)
const H           = 15;    // disk thickness
const GROOVE_W    = 5;     // groove width (along Z) at the outer rim
const GROOVE_D    = 4;     // groove depth (radial) — apex sits at r = R_OUTER - GROOVE_D
const R_BORE      = 4;     // 8 mm dia center bore
const KEYWAY_W    = 2;     // square keyway cross-section
const RIM_CHAMFER = 1;     // outer rim top/bottom chamfer

// --- 1. Body: flat disk, then chamfer the two outer rim edges
//     (BEFORE the boolean cuts — OCCT's chamfer solver is sensitive to
//     edge-graph complexity after cuts).
//     parallelToPlane:'XY' picks only the two horizontal rim circles
//     (not the vertical seam edge replicad puts on cylinder sides).
const body = BREP.label(
  BREP.cylinder(R_OUTER, H).chamfer(RIM_CHAMFER, { parallelToPlane: 'XY' }),
  'pulley',
  { color: '#e67e22' },
);

// --- 2. Carve a rectangular groove around the rim (a thin tall cylinder
//     punched through, intersected with a wider ring).
//     Construct it as (large outer cylinder − inner cylinder), giving
//     a ring of cross-section: width GROOVE_W along Z, depth GROOVE_D
//     inward from the rim.
const grooveZMin   = (H - GROOVE_W) / 2;          // z=4.5
const grooveZMax   = grooveZMin + GROOVE_W;       // z=10.5
const grooveOuterR = R_OUTER + 1;                 // 26 — pokes just past the rim
const grooveInnerR = R_OUTER - GROOVE_D;          // 21 — apex depth

const grooveOuter = BREP.cylinder(grooveOuterR, GROOVE_W).translate([0, 0, grooveZMin]);
const grooveInner = BREP.cylinder(grooveInnerR, GROOVE_W + 2).translate([0, 0, grooveZMin - 1]);
const grooveRing  = grooveOuter.cut(grooveInner);

// --- 3. Cut the rectangular groove, then chamfer the two new rim
//     edges of that groove so its cross-section becomes a V.
//     The two chamferable edges are the circles where the groove walls
//     meet the disk's outer surface — at z = grooveZMin and grooveZMax,
//     at radius R_OUTER (post-cut). A chamfer of (GROOVE_W/2) on each
//     bevels the wall down to a point at the midplane, producing a
//     45° V.
const VEXTENT = 1.5;                              // V-wall chamfer; leaves small flat at apex (avoids OCCT solver collisions)

let part = body.cut(grooveRing);

// Chamfer ONLY the two horizontal circles at the groove's top and
// bottom mouths — minZ/maxZ pin them, parallelToPlane keeps the
// vertical seam edge out.
part = part.chamfer(VEXTENT, {
  parallelToPlane: 'XY',
  minZ: grooveZMax - 0.01,
  maxZ: grooveZMax + 0.01,
});
part = part.chamfer(VEXTENT, {
  parallelToPlane: 'XY',
  minZ: grooveZMin - 0.01,
  maxZ: grooveZMin + 0.01,
});

// --- 4. Centre bore — 8 mm dia, slightly proud on both ends for a
//     clean cut surface.
const bore = BREP.cylinder(R_BORE, H + 2).translate([0, 0, -1]);

// --- 5. Small keyway slot alongside the bore — a 2×2 square channel
//     opening into the bore wall.
const keyway = BREP.box([KEYWAY_W, KEYWAY_W, H + 2])
  .translate([0, R_BORE + KEYWAY_W / 2 - 0.4, 0]);

return BREP.cutAll([part, bore, keyway]);
